SELECT usage_type, duration
FROM variant_usage
WHERE usage_id = 1;

SELECT COUNT(*) AS total_training_usage
FROM variant_usage
WHERE usage_type = 'training';

SELECT modification_id, description, status
FROM variant_modifications
WHERE status = 'completed';

SELECT variant_name, total_units_produced
FROM variants
WHERE total_units_produced = (SELECT MIN(total_units_produced) FROM variants);

SELECT SUM(duration) AS total_duration
FROM variant_usage
WHERE variant_id = 0;

SELECT COUNT(*) AS count_of_aggressive_variants
FROM variants
WHERE default_personality = (SELECT personality_id FROM personality_types WHERE personality_name = 'aggressive');
